const raw = $input.first().json.data || '{}';
const data = typeof raw === 'string' ? JSON.parse(raw) : raw;
return [{ json: data }];

const token     = $('Obtener Token SYSCOM').first().json.access_token;
const productos = $('Parsear Input').first().json.productos || [];
const allResults = [];

for (const producto of productos) {
  try {
    const resp = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://developers.syscom.mx/api/v1/productos',
      headers: { Authorization: `Bearer ${token}` },
      qs: { keyword: producto.searchQuery, limite: 5 }
    });

    const items = resp.productos || resp.data || resp || [];
    const list  = Array.isArray(items) ? items : [];

    for (const item of list.slice(0, 3)) {
      allResults.push({
        mayorista:       'SYSCOM',
        sku:             item.producto_id || item.codigo || '',
        skuFabricante:   item.numero_parte || '',
        descripcion:     item.titulo || item.descripcion || '',
        marca:           item.marca || producto.marca,
        precio:          Number(item.precios?.precio_lista || item.precio || 0),
        moneda:          'MXN',
        existencia:      Number(item.total_existencia || item.existencia || 0),
        disponible:      (item.total_existencia || 0) > 0,
        imagenUrl:       item.img_portada || '',
        productoBuscado: producto.searchQuery
      });
    }
  } catch(e) {
    allResults.push({ mayorista: 'SYSCOM', error: e.message, productoBuscado: producto.searchQuery });
  }
}

return allResults.map(r => ({ json: r }));
